assign	nC=~C;
assign	nA=~A;
wire	BC;
assign	BC=~(~B | ~C);
wire	nBnC;
assign	nBnC=nB&nC;
wire	nBanC;
assign	nBanC=nB|nC;
assign	double=(nBnC&A)|(BC&nA);
assign	negation=A&nBanC;
assign	zero=(A&BC)|(nA&nBnC);
endmodule

